PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE d1_migrations(
		id         INTEGER PRIMARY KEY AUTOINCREMENT,
		name       TEXT UNIQUE,
		applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);
CREATE TABLE vehicles (
  id TEXT PRIMARY KEY,
  vin TEXT UNIQUE NOT NULL,
  display_name TEXT,
  vehicle_type TEXT,
  model TEXT,
  year INTEGER,
  color TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE journeys (
  id TEXT PRIMARY KEY,
  vehicle_id TEXT NOT NULL,
  name TEXT NOT NULL,
  description TEXT,
  start_date DATE NOT NULL,
  end_date DATE,
  total_states INTEGER DEFAULT 0,
  target_states INTEGER DEFAULT 48,
  total_miles REAL DEFAULT 0,
  status TEXT DEFAULT 'active', 
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, states_visited INTEGER DEFAULT 0, total_drives INTEGER DEFAULT 0, last_updated TEXT,
  FOREIGN KEY (vehicle_id) REFERENCES vehicles(id)
);
CREATE TABLE vehicle_state (
  vehicle_id TEXT PRIMARY KEY,
  battery_level INTEGER,
  battery_range REAL,
  charging_state TEXT,
  latitude REAL,
  longitude REAL,
  heading REAL,
  speed REAL,
  odometer REAL,
  inside_temp REAL,
  outside_temp REAL,
  shift_state TEXT,
  power INTEGER,
  timestamp DATETIME,
  state_name TEXT,
  city TEXT,
  address TEXT,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (vehicle_id) REFERENCES vehicles(id)
);
CREATE TABLE drives (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  tessie_id INTEGER UNIQUE,
  vehicle_id TEXT NOT NULL,
  journey_id TEXT NOT NULL,
  started_at DATETIME NOT NULL,
  ended_at DATETIME NOT NULL,
  start_address TEXT,
  end_address TEXT,
  start_latitude REAL,
  start_longitude REAL,
  end_latitude REAL,
  end_longitude REAL,
  start_state TEXT,
  end_state TEXT,
  distance_miles REAL,
  duration_minutes INTEGER,
  energy_used_kwh REAL,
  average_speed REAL,
  max_speed REAL,
  outside_temp_avg REAL,
  start_battery_level INTEGER,
  end_battery_level INTEGER,
  start_range REAL,
  end_range REAL,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP, vin TEXT,
  FOREIGN KEY (vehicle_id) REFERENCES vehicles(id),
  FOREIGN KEY (journey_id) REFERENCES journeys(id)
);
CREATE TABLE charges (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  tessie_id INTEGER UNIQUE,
  vehicle_id TEXT NOT NULL,
  journey_id TEXT NOT NULL,
  started_at DATETIME NOT NULL,
  ended_at DATETIME,
  location TEXT,
  latitude REAL,
  longitude REAL,
  state_name TEXT,
  city TEXT,
  charger_type TEXT, 
  charger_power_kw REAL,
  energy_added_kwh REAL,
  charge_rate_avg REAL,
  charge_rate_max REAL,
  start_battery_level INTEGER,
  end_battery_level INTEGER,
  start_range REAL,
  end_range REAL,
  cost_usd REAL,
  duration_minutes INTEGER,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP, vin TEXT,
  FOREIGN KEY (vehicle_id) REFERENCES vehicles(id),
  FOREIGN KEY (journey_id) REFERENCES journeys(id)
);
CREATE TABLE states_visited (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  journey_id TEXT NOT NULL,
  state_name TEXT NOT NULL,
  state_code TEXT,
  first_visited_date DATE,
  first_drive_id INTEGER,
  visit_count INTEGER DEFAULT 1,
  total_miles_in_state REAL DEFAULT 0,
  total_time_minutes INTEGER DEFAULT 0,
  entry_latitude REAL,
  entry_longitude REAL,
  entry_address TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (journey_id) REFERENCES journeys(id),
  FOREIGN KEY (first_drive_id) REFERENCES drives(id),
  UNIQUE(journey_id, state_name)
);
CREATE TABLE media (
  id TEXT PRIMARY KEY,
  journey_id TEXT NOT NULL,
  vehicle_id TEXT NOT NULL,
  filename TEXT NOT NULL,
  original_filename TEXT,
  mime_type TEXT,
  file_size INTEGER,
  r2_object_key TEXT UNIQUE NOT NULL,
  title TEXT,
  description TEXT,
  latitude REAL,
  longitude REAL,
  state_name TEXT,
  city TEXT,
  address TEXT,
  taken_at DATETIME,
  drive_id INTEGER,
  charge_id INTEGER,
  tags TEXT, 
  is_favorite BOOLEAN DEFAULT FALSE,
  view_count INTEGER DEFAULT 0,
  upload_ip TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (journey_id) REFERENCES journeys(id),
  FOREIGN KEY (vehicle_id) REFERENCES vehicles(id),
  FOREIGN KEY (drive_id) REFERENCES drives(id),
  FOREIGN KEY (charge_id) REFERENCES charges(id)
);
CREATE TABLE api_cache (
  cache_key TEXT PRIMARY KEY,
  cache_data TEXT NOT NULL, 
  expires_at DATETIME NOT NULL,
  cache_type TEXT, 
  metadata TEXT, 
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE analytics_events (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  event_type TEXT NOT NULL, 
  event_data TEXT, 
  user_ip TEXT,
  user_agent TEXT,
  timestamp DATETIME DEFAULT CURRENT_TIMESTAMP,
  processing_time_ms INTEGER,
  status_code INTEGER
);
CREATE TABLE job_queue (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  job_type TEXT NOT NULL, 
  job_data TEXT NOT NULL, 
  status TEXT DEFAULT 'pending', 
  attempts INTEGER DEFAULT 0,
  max_attempts INTEGER DEFAULT 3,
  error_message TEXT,
  scheduled_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  started_at DATETIME,
  completed_at DATETIME,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE vehicle_states (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  vin TEXT NOT NULL,
  timestamp TEXT NOT NULL,
  battery_level INTEGER DEFAULT 0,
  battery_range REAL DEFAULT 0,
  charging_state TEXT DEFAULT 'Unknown',
  latitude REAL DEFAULT 0,
  longitude REAL DEFAULT 0,
  heading REAL DEFAULT 0,
  speed REAL DEFAULT 0,
  odometer REAL DEFAULT 0,
  inside_temp REAL,
  outside_temp REAL,
  locked BOOLEAN DEFAULT FALSE,
  climate_on BOOLEAN DEFAULT FALSE,
  raw_data TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE journey_overview (
  id TEXT PRIMARY KEY,
  journey_id TEXT NOT NULL,
  total_miles INTEGER NOT NULL,
  current_odometer INTEGER NOT NULL,
  trip_miles INTEGER NOT NULL,
  days_elapsed INTEGER NOT NULL,
  states_visited_count INTEGER NOT NULL,
  journey_start_date TEXT NOT NULL,
  journey_end_date TEXT,
  status TEXT NOT NULL DEFAULT 'active',
  last_updated TEXT NOT NULL,
  created_at TEXT DEFAULT (datetime('now'))
);
CREATE TABLE current_status (
  id TEXT PRIMARY KEY,
  vehicle_id TEXT NOT NULL,
  battery_level INTEGER NOT NULL,
  battery_range INTEGER NOT NULL,
  charging_status TEXT NOT NULL,
  current_speed INTEGER NOT NULL,
  current_city TEXT,
  current_state TEXT,
  current_latitude REAL,
  current_longitude REAL,
  inside_temp_f INTEGER,
  outside_temp_f INTEGER,
  is_locked BOOLEAN,
  is_climate_on BOOLEAN,
  last_updated TEXT NOT NULL,
  created_at TEXT DEFAULT (datetime('now'))
);
CREATE TABLE states_progress (
  id TEXT PRIMARY KEY,
  journey_id TEXT NOT NULL,
  state_name TEXT NOT NULL,
  state_abbreviation TEXT NOT NULL,
  first_visited_date TEXT NOT NULL,
  visit_order INTEGER,
  total_miles_in_state REAL,
  cities_visited TEXT,
  is_current_state BOOLEAN DEFAULT FALSE,
  last_updated TEXT NOT NULL,
  created_at TEXT DEFAULT (datetime('now'))
);
CREATE TABLE recent_drives_summary (
  id TEXT PRIMARY KEY,
  journey_id TEXT NOT NULL,
  drive_date TEXT NOT NULL,
  start_city TEXT NOT NULL,
  start_state TEXT NOT NULL,
  end_city TEXT NOT NULL,
  end_state TEXT NOT NULL,
  distance_miles REAL NOT NULL,
  duration_hours REAL NOT NULL,
  energy_used_kwh REAL,
  average_speed_mph INTEGER,
  drive_order INTEGER,
  last_updated TEXT NOT NULL,
  created_at TEXT DEFAULT (datetime('now'))
);
CREATE TABLE journey_waypoints (
      id TEXT PRIMARY KEY,
      journey_id TEXT,
      drive_id TEXT,
      latitude REAL,
      longitude REAL,
      state_name TEXT,
      city_name TEXT,
      address TEXT,
      waypoint_type TEXT, -- 'start', 'end', 'charging', 'overnight'
      timestamp TEXT,
      created_at TEXT DEFAULT CURRENT_TIMESTAMP
    );
CREATE TABLE states_visited_historical (
      id TEXT PRIMARY KEY,
      journey_id TEXT,
      state_name TEXT,
      state_abbreviation TEXT,
      first_visited_date TEXT,
      coordinates_first_visit TEXT,
      visit_count INTEGER DEFAULT 1,
      total_miles_in_state REAL DEFAULT 0,
      created_at TEXT DEFAULT CURRENT_TIMESTAMP
    );
DELETE FROM sqlite_sequence;
CREATE INDEX idx_drives_vehicle_journey ON drives(vehicle_id, journey_id);
CREATE INDEX idx_drives_dates ON drives(started_at, ended_at);
CREATE INDEX idx_drives_states ON drives(start_state, end_state);
CREATE INDEX idx_charges_vehicle_journey ON charges(vehicle_id, journey_id);
CREATE INDEX idx_charges_dates ON charges(started_at, ended_at);
CREATE INDEX idx_states_visited_journey ON states_visited(journey_id);
CREATE INDEX idx_media_journey ON media(journey_id);
CREATE INDEX idx_media_location ON media(latitude, longitude);
CREATE INDEX idx_api_cache_expires ON api_cache(expires_at);
CREATE INDEX idx_analytics_timestamp ON analytics_events(timestamp);
CREATE INDEX idx_job_queue_status ON job_queue(status, scheduled_at);
CREATE INDEX idx_vehicle_states_vin_timestamp ON vehicle_states(vin, timestamp);
CREATE INDEX idx_journey_overview_journey_id ON journey_overview (journey_id);
CREATE INDEX idx_current_status_vehicle_id ON current_status (vehicle_id);
CREATE INDEX idx_states_progress_journey_id ON states_progress (journey_id);
CREATE INDEX idx_recent_drives_journey_id ON recent_drives_summary (journey_id);
CREATE INDEX idx_recent_drives_order ON recent_drives_summary (journey_id, drive_order);
